const recent =
  $('HTTP Request | Eco Calendar Recent - Finnhub').first().json.economicCalendar || [];

const upcoming =
  $('HTTP Request | Eco Calendar Upcoming - Finnhub').first().json.economicCalendar || [];

// Tier-1 US indicators with sigma values for surprise normalisation
const TIER1 = {
  'Non Farm Payrolls':           { key: 'NFP',            sigma: 80 },
  'Average Hourly Earnings MoM': { key: 'AHE_MOM',        sigma: 0.1 },
  'Unemployment Rate':           { key: 'UNEMPLOYMENT',   sigma: 0.15 },
  'Core Inflation Rate MoM':     { key: 'CORE_CPI_MOM',   sigma: 0.1 },
  'Inflation Rate MoM':          { key: 'CPI_MOM',        sigma: 0.15 },
  'ISM Manufacturing PMI':       { key: 'ISM_MFG',        sigma: 2.5 },
  'ISM Services PMI':            { key: 'ISM_SVCS',       sigma: 2.5 },
  'GDP Growth Rate QoQ Adv':     { key: 'GDP_ADV',        sigma: 0.5 },
  'ADP Employment Change':       { key: 'ADP',            sigma: 50 },
  'Initial Jobless Claims':      { key: 'JOBLESS_CLAIMS', sigma: 15 },
  'JOLTs Job Openings':          { key: 'JOLTS',          sigma: 0.3 }
};

const EZ_COUNTRIES = ['EA', 'DE', 'FR', 'IT', 'ES'];

function isHighMedium(e) {
  return ['high', 'medium'].includes(String(e.impact || '').toLowerCase());
}

function hasActual(e) {
  return e.actual !== null && e.actual !== undefined && e.actual !== '';
}

function noActual(e) {
  return e.actual === null || e.actual === undefined || e.actual === '';
}

function cleanDate(time) {
  return String(time || '').split(' ')[0] || null;
}

function cleanRecentEvent(e) {
  return {
    event: e.event,
    country: e.country || null,
    time: cleanDate(e.time),
    actual: e.actual ?? null,
    estimate: e.estimate ?? null,
    prev: e.prev ?? null,
    impact: e.impact || null
  };
}

function cleanUpcomingEvent(e) {
  return {
    event: e.event,
    country: e.country || null,
    time: e.time || null,
    estimate: e.estimate ?? null,
    impact: e.impact || null
  };
}

// US recent high/medium impact events with actuals
const recentUS = recent.filter(e =>
  e.country === 'US' &&
  isHighMedium(e) &&
  hasActual(e)
);

// US upcoming high/medium impact events without actuals
const upcomingUS = upcoming.filter(e =>
  e.country === 'US' &&
  isHighMedium(e) &&
  noActual(e)
);

// Eurozone / major EZ country recent high/medium impact events with actuals
const recentEZ = recent.filter(e =>
  EZ_COUNTRIES.includes(e.country) &&
  isHighMedium(e) &&
  hasActual(e)
);

// Eurozone / major EZ country upcoming high/medium impact events without actuals
const upcomingEZ = upcoming.filter(e =>
  EZ_COUNTRIES.includes(e.country) &&
  isHighMedium(e) &&
  noActual(e)
);

// Compute surprise scores for tier-1 recent US prints
const surprises = [];

for (const event of recentUS) {
  const tier1 = TIER1[event.event];
  if (!tier1) continue;
  if (event.actual === null || event.estimate === null) continue;

  const surprise = (event.actual - event.estimate) / tier1.sigma;

  surprises.push({
    key: tier1.key,
    event: event.event,
    date: cleanDate(event.time),
    actual: event.actual,
    estimate: event.estimate,
    surprise: Math.round(surprise * 100) / 100,
    direction: surprise > 0 ? 'BEAT' : surprise < 0 ? 'MISS' : 'IN LINE'
  });
}

// Existing US upcoming calendar
const calendar = upcomingUS.map(cleanUpcomingEvent);

// Existing US recent summary
const recentSummary = recentUS.slice(-20).map(cleanRecentEvent);

// New EUR datasets
const ezCalendar = upcomingEZ.map(cleanUpcomingEvent);
const ezRecentSummary = recentEZ.slice(-20).map(cleanRecentEvent);

return [{
  json: {
    raw_recent_count: recent.length,
    raw_upcoming_count: upcoming.length,

    recent_country_counts: recent.reduce((acc, e) => {
      const c = e.country || 'UNKNOWN';
      acc[c] = (acc[c] || 0) + 1;
      return acc;
    }, {}),

    upcoming_country_counts: upcoming.reduce((acc, e) => {
      const c = e.country || 'UNKNOWN';
      acc[c] = (acc[c] || 0) + 1;
      return acc;
    }, {}),

    sample_recent_events: recent.slice(0, 20).map(e => ({
