  e.country === 'US' &&
  isHighMedium(e) &&
  hasActual(e)
);

// US upcoming high/medium impact events without actuals
const upcomingUS = upcoming.filter(e =>
  e.country === 'US' &&
  isHighMedium(e) &&
  noActual(e)
);

// Eurozone / major EZ country recent high/medium impact events with actuals
const recentEZ = recent.filter(e =>
  EZ_COUNTRIES.includes(e.country) &&
  isHighMedium(e) &&
  hasActual(e)
);

// Eurozone / major EZ country upcoming high/medium impact events without actuals
const upcomingEZ = upcoming.filter(e =>
  EZ_COUNTRIES.includes(e.country) &&
  isHighMedium(e) &&
  noActual(e)
);

// Compute surprise scores for tier-1 recent US prints
const surprises = [];

for (const event of recentUS) {
  const tier1 = TIER1[event.event];
  if (!tier1) continue;
  if (event.actual === null || event.estimate === null) continue;

  const surprise = (event.actual - event.estimate) / tier1.sigma;

  surprises.push({
    key: tier1.key,
    event: event.event,
    date: cleanDate(event.time),
    actual: event.actual,
    estimate: event.estimate,
    surprise: Math.round(surprise * 100) / 100,
    direction: surprise > 0 ? 'BEAT' : surprise < 0 ? 'MISS' : 'IN LINE'
  });
}

// Existing US upcoming calendar
const calendar = upcomingUS.map(cleanUpcomingEvent);

// Existing US recent summary
const recentSummary = recentUS.slice(-20).map(cleanRecentEvent);

// New EUR datasets
const ezCalendar = upcomingEZ.map(cleanUpcomingEvent);
const ezRecentSummary = recentEZ.slice(-20).map(cleanRecentEvent);

return [{
  json: {
    raw_recent_count: recent.length,
    raw_upcoming_count: upcoming.length,

    recent_country_counts: recent.reduce((acc, e) => {
      const c = e.country || 'UNKNOWN';
      acc[c] = (acc[c] || 0) + 1;
      return acc;
    }, {}),

    upcoming_country_counts: upcoming.reduce((acc, e) => {
      const c = e.country || 'UNKNOWN';
      acc[c] = (acc[c] || 0) + 1;
      return acc;
    }, {}),

    sample_recent_events: recent.slice(0, 20).map(e => ({
      country: e.country,
      event: e.event,
      time: e.time,
      impact: e.impact,
      actual: e.actual,
      estimate: e.estimate
    })),

    sample_upcoming_events: upcoming.slice(0, 20).map(e => ({
      country: e.country,
      event: e.event,
      time: e.time,
      impact: e.impact,
      actual: e.actual,
      estimate: e.estimate
    }))
  }
}];

const eco = $('Code | Process Eco Data').first().json;

const surprises = eco.surprises || [];

let score = 0;
const reasons = [];

for (const s of surprises) {
  if (s.direction === "BEAT") {
    score += 1;
    reasons.push(`${s.event} beat forecast`);
  }

  if (s.direction === "MISS") {
    score -= 1;
    reasons.push(`${s.event} missed forecast`);
  }
}

let fed_bias = "neutral";

if (score >= 2) fed_bias = "hawkish";
if (score <= -2) fed_bias = "dovish";

return [
  {
    json: {
      fed_bias,
      fed_bias_score: score,
      fed_bias_reasons: reasons.slice(0, 5)
    }
  }
];

function impactRank(impact) {
  const s = String(impact || '').toLowerCase();
  if (s.includes('high')) return 3;
  if (s.includes('medium')) return 2;
  if (s.includes('low')) return 1;
  return 0;
}

function priority(name) {
  const n = String(name || '').toLowerCase();

  if (n.includes('ecb')) return 100;
  if (n.includes('cpi') || n.includes('inflation')) return 98;
  if (n.includes('pmi')) return 95;
  if (n.includes('gdp')) return 90;
  if (n.includes('zew')) return 85;
  if (n.includes('ifo')) return 85;
  if (n.includes('retail sales')) return 80;
  if (n.includes('industrial production')) return 75;
  if (n.includes('unemployment')) return 70;
  if (n.includes('bond auction')) return 65;

  return 50;
}

function eventTime(e) {
  return `${e.event_date || ''} ${e.event_time_text || '00:00'}`;
}

const events = $input.all().map(i => i.json);

const completed = events
  .filter(e => e.actual !== null && e.actual !== undefined && e.actual !== '')
  .map(e => ({
    event: e.event_name,
    actual: e.actual,
    forecast: e.forecast,
    previous: e.previous,
    surprise: e.surprise_direction,
    eur_signal: e.currency_signal,
    date: e.event_date,
    time: e.event_time_text,
    impact: e.impact,
    priority: priority(e.event_name),
    impact_rank: impactRank(e.impact),
    raw: e
  }))
  .sort((a, b) => {
    const timeDiff = new Date(eventTime(b.raw)) - new Date(eventTime(a.raw));
    if (timeDiff !== 0) return timeDiff;
    return b.priority - a.priority;
  });

const upcoming_ez_events = events
  .filter(e => e.actual === null || e.actual === undefined || e.actual === '')
  .map(e => ({
    event: e.event_name,
    forecast: e.forecast,
    previous: e.previous,
    date: e.event_date,
    time: e.event_time_text,
    impact: e.impact,
    priority: priority(e.event_name),
    impact_rank: impactRank(e.impact)
  }))
  .sort((a, b) => String(a.time || '').localeCompare(String(b.time || '')))
  .slice(0, 10);

const latest_ez_event = completed[0] || null;

let ecb_bias_score = 0;
const ecb_bias_reasons = [];

for (const e of completed.slice(0, 8)) {
  const weight = e.impact_rank >= 3 ? 2 : 1;

  if (e.eur_signal === 'BULLISH') {
    ecb_bias_score += weight;
    ecb_bias_reasons.push(`${e.event} beat forecast`);
  }

  if (e.eur_signal === 'BEARISH') {
    ecb_bias_score -= weight;
    ecb_bias_reasons.push(`${e.event} missed forecast`);
  }
}

let ecb_bias = 'neutral';
if (ecb_bias_score >= 2) ecb_bias = 'hawkish';
if (ecb_bias_score <= -2) ecb_bias = 'dovish';

return [{
  json: {
    latest_ez_event,
    upcoming_ez_events,
    ecb_bias,
    ecb_bias_score,
    ecb_bias_reasons,
    recentEzSummary: completed,
    ezCalendar: upcoming_ez_events,
    source: 'economic_events',
    data_quality: {
      eur_events_found: events.length,
      completed_eur_events_found: completed.length,
      upcoming_eur_events_found: upcoming_ez_events.length
    }
  }
}];

function num(v) {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(String(v).replace('%', '').replace(',', '').trim());
  return Number.isFinite(n) ? n : null;
}

const events = $input.all().map(i => i.json)
  .filter(e => String(e.event_name || '').toLowerCase().includes('pmi'))
  .filter(e => e.actual !== null && e.actual !== undefined && e.actual !== '')
  .sort((a, b) => new Date(b.event_date) - new Date(a.event_date));

const priority = [
  'final services pmi',
  'final manufacturing pmi',
  'services pmi',
  'manufacturing pmi'
];

function eventPriority(name) {
  const n = String(name || '').toLowerCase();
  const idx = priority.findIndex(p => n.includes(p));
  return idx === -1 ? 99 : idx;
}

events.sort((a, b) => {
  const dateDiff = new Date(b.event_date) - new Date(a.event_date);
  if (dateDiff !== 0) return dateDiff;
  return eventPriority(a.event_name) - eventPriority(b.event_name);
});

const latest = events[0] || null;
const actual = num(latest?.actual);
const previous = num(latest?.previous);

let direction = null;

if (actual !== null && previous !== null) {
  if (actual > previous) direction = 'improving';
  else if (actual < previous) direction = 'deteriorating';
  else direction = 'stable';
}

return [{
  json: {
    ez_composite_pmi: actual,
    ez_composite_pmi_direction: direction,
    latest_ez_pmi_event: latest,
    eur_pmi_events_found: events.length
  }
}];
